// T040-T042: Dual-token tracking, automated refresh, refresh token monitoring
// LinkedIn access tokens: 60-day TTL
// LinkedIn refresh tokens: 365-day TTL
// Consolidated logic shared by Schedule and Webhook paths

const staticData = $getWorkflowStaticData('global');

// 019: Read hook token from Static Data (not $env)
const hookToken = staticData.hookToken || '';
const now = new Date();
const ONE_DAY_MS = 1000 * 60 * 60 * 24;

// --- Initialize timestamps on first run ---
if (!staticData.access_token_granted_at) {
  // Migrate from legacy grant_timestamp if present
  if (staticData.grant_timestamp) {
    staticData.access_token_granted_at = staticData.grant_timestamp;
    staticData.refresh_token_granted_at = staticData.grant_timestamp;
    delete staticData.grant_timestamp;
  } else {
    staticData.access_token_granted_at = now.toISOString();
    staticData.refresh_token_granted_at = now.toISOString();
  }
}
if (!staticData.refresh_token_granted_at) {
  staticData.refresh_token_granted_at = staticData.access_token_granted_at;
}

// --- Compute days remaining for both tokens ---
const accessGrantDate = new Date(staticData.access_token_granted_at);
const refreshGrantDate = new Date(staticData.refresh_token_granted_at);

const accessDaysSinceGrant = Math.floor((now - accessGrantDate) / ONE_DAY_MS);
const refreshDaysSinceGrant = Math.floor((now - refreshGrantDate) / ONE_DAY_MS);

const access_token_days_remaining = Math.max(60 - accessDaysSinceGrant, 0);
const refresh_token_days_remaining = Math.max(365 - refreshDaysSinceGrant, 0);

const accessExpiryDate = new Date(accessGrantDate);
accessExpiryDate.setDate(accessExpiryDate.getDate() + 60);

const refreshExpiryDate = new Date(refreshGrantDate);
refreshExpiryDate.setDate(refreshExpiryDate.getDate() + 365);

// --- Initialize retry and flag state ---
if (typeof staticData.refresh_retry_count !== 'number') {
  staticData.refresh_retry_count = 0;
}
if (typeof staticData.refresh_in_progress !== 'boolean') {
  staticData.refresh_in_progress = false;
}
if (typeof staticData.refresh_token_expired !== 'boolean') {
  staticData.refresh_token_expired = false;
}

// --- T042: Refresh token expiry monitoring ---
let alert_type = null;
let alert_message = null;
let alert_severity = 'info';

if (refresh_token_days_remaining <= 0) {
  staticData.refresh_token_expired = true;
  alert_type = 'refresh_token_expired';
  alert_message = 'LinkedIn refresh token has expired. Manual re-authorization required.';
  alert_severity = 'critical';
} else if (refresh_token_days_remaining <= 30) {
  alert_type = 'refresh_token_expiring';
  alert_message = `LinkedIn refresh token expires in ${refresh_token_days_remaining} days (${refreshExpiryDate.toISOString().split('T')[0]}). Plan re-authorization.`;
  alert_severity = 'warning';
}

// --- T041: Determine if automated refresh is needed ---
let should_refresh = false;

if (access_token_days_remaining <= 7
    && !staticData.refresh_in_progress
    && !staticData.refresh_token_expired
    && refresh_token_days_remaining > 0) {
  should_refresh = true;
}

// --- T041: Access token alert (only if refresh not possible) ---
if (access_token_days_remaining <= 7 && !should_refresh && !alert_type) {
  alert_type = 'token_expiring';
  alert_message = `LinkedIn access token expires in ${access_token_days_remaining} days (${accessExpiryDate.toISOString().split('T')[0]}). Automated refresh unavailable — manual re-authorization required.`;
  alert_severity = 'warning';
}

// Determine overall status
let status = 'healthy';
if (refresh_token_days_remaining <= 0) {
  status = 'refresh_token_expired';
} else if (access_token_days_remaining <= 0) {
  status = 'expired';
} else if (access_token_days_remaining <= 7) {
  status = 'expiring_soon';
} else if (refresh_token_days_remaining <= 30) {
  status = 'refresh_expiring_soon';
}

// Set refresh_in_progress flag before passing to refresh node
if (should_refresh) {
  staticData.refresh_in_progress = true;
}

return [{
  json: {
    status,
    access_token_days_remaining,
    access_token_grant_date: accessGrantDate.toISOString().split('T')[0],
    access_token_expiry_date: accessExpiryDate.toISOString().split('T')[0],
    refresh_token_days_remaining,
    refresh_token_grant_date: refreshGrantDate.toISOString().split('T')[0],
    refresh_token_expiry_date: refreshExpiryDate.toISOString().split('T')[0],
    should_refresh,
    refresh_in_progress: staticData.refresh_in_progress,
    refresh_token_expired: staticData.refresh_token_expired,
    alert_needed: !!alert_type,
    alert_type,
    alert_message,
    alert_severity
  }
}];

// Check Token (Webhook) — delegates to same logic as Schedule path
// This node exists because the webhook path needs its own entry point
// but the logic is identical to the Schedule path's Check Token node.

const staticData = $getWorkflowStaticData('global');
const now = new Date();
const ONE_DAY_MS = 1000 * 60 * 60 * 24;

// --- Initialize timestamps on first run ---
if (!staticData.access_token_granted_at) {
  if (staticData.grant_timestamp) {
    staticData.access_token_granted_at = staticData.grant_timestamp;
    staticData.refresh_token_granted_at = staticData.grant_timestamp;
    delete staticData.grant_timestamp;
  } else {
    staticData.access_token_granted_at = now.toISOString();
    staticData.refresh_token_granted_at = now.toISOString();
  }
}
if (!staticData.refresh_token_granted_at) {
  staticData.refresh_token_granted_at = staticData.access_token_granted_at;
}

const accessGrantDate = new Date(staticData.access_token_granted_at);
const refreshGrantDate = new Date(staticData.refresh_token_granted_at);

const accessDaysSinceGrant = Math.floor((now - accessGrantDate) / ONE_DAY_MS);
const refreshDaysSinceGrant = Math.floor((now - refreshGrantDate) / ONE_DAY_MS);

const access_token_days_remaining = Math.max(60 - accessDaysSinceGrant, 0);
const refresh_token_days_remaining = Math.max(365 - refreshDaysSinceGrant, 0);

const accessExpiryDate = new Date(accessGrantDate);
accessExpiryDate.setDate(accessExpiryDate.getDate() + 60);

const refreshExpiryDate = new Date(refreshGrantDate);
refreshExpiryDate.setDate(refreshExpiryDate.getDate() + 365);

let status = 'healthy';
if (refresh_token_days_remaining <= 0) {
  status = 'refresh_token_expired';
} else if (access_token_days_remaining <= 0) {
  status = 'expired';
} else if (access_token_days_remaining <= 7) {
  status = 'expiring_soon';
} else if (refresh_token_days_remaining <= 30) {
  status = 'refresh_expiring_soon';
}

return [{
  json: {
    status,
    access_token_days_remaining,
    access_token_grant_date: accessGrantDate.toISOString().split('T')[0],
    access_token_expiry_date: accessExpiryDate.toISOString().split('T')[0],
    refresh_token_days_remaining,
    refresh_token_grant_date: refreshGrantDate.toISOString().split('T')[0],
    refresh_token_expiry_date: refreshExpiryDate.toISOString().split('T')[0],
    refresh_token_expired: !!staticData.refresh_token_expired,
    last_refresh_result: staticData.last_refresh_result || 'not_attempted'
  }
}];

// T041: Handle OAuth refresh response
// Processes success and error cases from the LinkedIn token refresh

const staticData = $getWorkflowStaticData('global');
const input = $input.first().json;
const now = new Date();

// Clear refresh_in_progress flag
staticData.refresh_in_progress = false;

// Check if the HTTP request succeeded
const statusCode = input.statusCode || (input.headers ? 200 : 0);
const body = input.body || input;

let result = {
  refresh_success: false,
  alert_needed: false,
  alert_type: null,
  alert_message: null,
  alert_severity: 'error'
};

if (statusCode >= 200 && statusCode < 300 && body.access_token) {
  // --- SUCCESS: Update grant timestamp ---
  staticData.access_token_granted_at = now.toISOString();
  staticData.last_refresh_attempt = now.toISOString();
  staticData.last_refresh_result = 'success';
  staticData.refresh_retry_count = 0;

  result.refresh_success = true;
  result.alert_needed = false;
  result.new_access_token_expiry = new Date(now.getTime() + 60 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];

} else {
  // --- FAILURE: Classify error and determine retry/alert ---
  staticData.last_refresh_attempt = now.toISOString();
  staticData.last_refresh_result = 'failed';

  const errorType = body.error || '';
  const errorDescription = body.error_description || '';

  if (errorType === 'invalid_grant') {
    // Refresh token revoked or expired — no retry, alert immediately
    staticData.refresh_token_expired = true;
    staticData.refresh_retry_count = 0;
    result.alert_needed = true;
    result.alert_type = 'token_refresh_failed';
    result.alert_message = `LinkedIn token refresh failed: refresh token revoked or expired. Manual re-authorization required. (${errorDescription})`;
    result.alert_severity = 'critical';

  } else if (errorType === 'invalid_client') {
    // Client credentials wrong — no retry, alert immediately
    staticData.refresh_retry_count = 0;
    result.alert_needed = true;
    result.alert_type = 'token_refresh_failed';
    result.alert_message = `LinkedIn token refresh failed: invalid client credentials. Verify client_id and client_secret in n8n LinkedIn OAuth2 credential. (${errorDescription})`;
    result.alert_severity = 'critical';

  } else if (statusCode >= 500) {
    // Server error — retry up to 3 times
    staticData.refresh_retry_count = (staticData.refresh_retry_count || 0) + 1;
    if (staticData.refresh_retry_count >= 3) {
      result.alert_needed = true;
      result.alert_type = 'token_refresh_failed';
      result.alert_message = `LinkedIn token refresh failed after 3 retries (HTTP ${statusCode}). Server-side error — will retry on next scheduled run.`;
      result.alert_severity = 'error';
      staticData.refresh_retry_count = 0;
    } else {
      // Will retry on next scheduled run
      result.alert_needed = false;
      result.retry_pending = true;
      result.retry_count = staticData.refresh_retry_count;
    }

  } else {
    // Network error or unknown — retry once then alert
    staticData.refresh_retry_count = (staticData.refresh_retry_count || 0) + 1;
    if (staticData.refresh_retry_count >= 2) {
      result.alert_needed = true;
      result.alert_type = 'token_refresh_failed';
      result.alert_message = `LinkedIn token refresh failed after retry (${errorType || 'network/unknown error'}). ${errorDescription || 'Check network connectivity and LinkedIn API status.'}`;
      result.alert_severity = 'error';
      staticData.refresh_retry_count = 0;
    } else {
      result.alert_needed = false;
      result.retry_pending = true;
      result.retry_count = staticData.refresh_retry_count;
    }
  }
}

return [{ json: result }];
